{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem is a geometric packing/optimization problem. I will split it into a strategy designer and a code implementation specialist.",
  "helpers": [
    {
      "label": "strategy_designer",
      "instructions": "Propose a geometric algorithm to generate non-overlapping axis-aligned rectangles that contain specific points (xi, yi) and approximate target areas (ri) within a 10000x10000 grid. Consider approaches like a sweep-line algorithm, a recursive quadtree-style subdivision, or a greedy approach where rectangles are expanded until they hit a boundary or another rectangle. The strategy must guarantee no overlaps and that all rectangles stay within [0, 10000). Provide the logic in pseudocode or a step-by-step mathematical description."
    },
    {
      "label": "code_implementer",
      "instructions": "Based on the strategy provided by the strategy_designer, write a complete, production-ready Python script named main.py. The script must read N and then N lines of (xi, yi, ri) from stdin. It must output N lines of 'x1 y1 x2 y2' representing the rectangle [x1, x2) x [y1, y2). Ensure the code handles the 10000x10000 boundary constraints, ensures no overlaps, and ensures each rectangle contains its respective (xi, yi). The code must be clean, efficient, and follow the exact output format required by the problem."
    }
  ],
  "synthesis_brief": "The parent will take the geometric strategy to ensure the mathematical validity of the non-overlapping constraint and then use the implementation provided by the coder to produce the final main.py file."
}

